output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?player ?nickname WHERE {
  ?series rdfs:label "The Match" @en ; wdt:P31 wd:Q7325 .
  ?series wdt:P161 ?player .
  ?player wdt:P2056 ?pos1 .
  ?player wdt:P2056 ?pos2 .
  FILTER(?pos1 != ?pos2)
  OPTIONAL {
    ?player wdt:P1448 ?nickname
  }
}

